import React, { useState, useEffect } from 'react';
import ProductService from './ProductService';
import { addUser, getAllUsers, deleteUser } from './UserService';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [pricePerDay, setPricePerDay] = useState('');
  const [mainImageFile, setMainImageFile] = useState(null);
  const [additionalImageFiles, setAdditionalImageFiles] = useState([]);
  const [category, setCategory] = useState('Clothing');
  const [subcategory, setSubcategory] = useState('Men');
  const [users, setUsers] = useState([]);
  const [applications, setApplications] = useState([]);

  useEffect(() => {
    fetchUsers();
    fetchSupplierApplications();
  }, []);

  const fetchUsers = async () => {
    try {
      const usersList = await getAllUsers();
      setUsers(usersList);
    } catch (error) {
      console.error('Error fetching users:', error);
    }
  };

  const fetchSupplierApplications = async () => {
    try {
      const usersList = await getAllUsers();
      const supplierApps = usersList.filter(user => user.supplierRequest === 'pending');
      setApplications(supplierApps);
    } catch (error) {
      console.error('Error fetching supplier applications:', error);
    }
  };

  const handleAdditionalImagesChange = (e) => {
    setAdditionalImageFiles(e.target.files);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const newProduct = {
      name,
      description,
      pricePerDay: parseInt(pricePerDay, 10),
      category,
      subcategory
    };

    try {
      await ProductService.addProduct(newProduct, mainImageFile, additionalImageFiles);
      setName('');
      setDescription('');
      setPricePerDay('');
      setMainImageFile(null);
      setAdditionalImageFiles([]);
    } catch (error) {
      console.error("Error adding product:", error);
    }
  };

  const handleDeleteUser = async (userId) => {
    try {
      await deleteUser(userId);
      setUsers(users.filter(user => user.id !== userId));
    } catch (error) {
      console.error('Error deleting user:', error);
    }
  };

  const handleApproveApplication = async (userId) => {
    try {
      const userDocRef = doc(db, 'users', userId);
      await setDoc(userDocRef, { supplierRequest: 'approved' }, { merge: true });
      alert('Application approved.');
      fetchSupplierApplications(); // Refresh the applications list
    } catch (error) {
      console.error('Error approving application:', error);
    }
  };

  const handleDenyApplication = async (userId) => {
    try {
      const userDocRef = doc(db, 'users', userId);
      await setDoc(userDocRef, { supplierRequest: 'denied' }, { merge: true });
      alert('Application denied.');
      fetchSupplierApplications(); // Refresh the applications list
    } catch (error) {
      console.error('Error denying application:', error);
    }
  };

  return (
    <div className="admin-dashboard">
      <div className="form-container">
        <form onSubmit={handleSubmit} className="add-product-form">
          <label>
            Name:
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
            />
          </label>
          <label>
            Description:
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
            />
          </label>
          <label>
            Price per Day:
            <input
              type="number"
              value={pricePerDay}
              onChange={(e) => setPricePerDay(e.target.value)}
              required
            />
          </label>
          <label>
            Main Image:
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setMainImageFile(e.target.files[0])}
              required
            />
          </label>
          <label>
            Additional Images:
            <input
              type="file"
              accept="image/*"
              multiple
              onChange={handleAdditionalImagesChange}
            />
            {additionalImageFiles.length > 0 && (
              <div className="image-preview">
                {Array.from(additionalImageFiles).map((file, index) => (
                  <img key={index} src={URL.createObjectURL(file)} alt={`Additional ${index + 1}`} />
                ))}
              </div>
            )}
          </label>
          <label>
            Category:
            <select
              value={category}
              onChange={(e) => setCategory(e.target.value)}
            >
              <option value="Clothing">Clothing</option>
              <option value="Footwear">Footwear</option>
              <option value="Gear">Gear</option>
              <option value="Accessories">Accessories</option>
            </select>
          </label>
          <label>
            Subcategory:
            <select
              value={subcategory}
              onChange={(e) => setSubcategory(e.target.value)}
            >
              {/* Options based on selected category */}
              {/* ... */}
            </select>
          </label>
          <button type="submit">Add Product</button>
        </form>
      </div>
      <div className="applications-container">
        <h2>Supplier Applications</h2>
        <ul>
          {applications.map(app => (
            <li key={app.id}>
              <p>{app.name} ({app.email}) - {app.supplierRequest}</p>
              <button onClick={() => handleApproveApplication(app.id)}>Approve</button>
              <button onClick={() => handleDenyApplication(app.id)}>Deny</button>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default AdminDashboard;
